/**
 * Generate ZeptoMail firewall config.
 *
 * Data source: https://www.zoho.com/zeptomail/help/api/email-sending.html
 *
 * ZeptoMail is Zoho's transactional email delivery service.
 * Uses Zoho-enczapikey authorization (not Bearer).
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.zoho.com/zeptomail/help/api/email-sending.html";
// Format: 32 lowercase alphanumeric chars (e.g. uxvst6gadzc32bjd6a7g89g21f725bd3)
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCo";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from ZeptoMail API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:zeptomail",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const zeptomailFirewall = {",
    '  name: "zeptomail",',
    '  description: "ZeptoMail API",',
    "  placeholders: {",
    `    ZEPTOMAIL_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.zeptomail.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Zoho-enczapikey ${{ secrets.ZEPTOMAIL_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating ZeptoMail firewall config...");
  const ts = generateTypeScript();
  writeOutput("zeptomail", ts, import.meta.dirname);
}
